import{_ as t,c as a,o as l,ah as i,g6 as n}from"./chunks/framework.BZunv3CL.js";const m=JSON.parse('{"title":"Installing and Activating License","description":"","frontmatter":{},"headers":[],"relativePath":"en_US/installation/license-install/license-install.md","filePath":"en_US/installation/license-install/license-install.md"}'),o={name:"en_US/installation/license-install/license-install.md"};function s(r,e,c,d,p,h){return l(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="installing-and-activating-license" tabindex="-1">Installing and Activating License <a class="header-anchor" href="#installing-and-activating-license" aria-label="Permalink to “Installing and Activating License”">​</a></h1><p>GridBeat is an open source project. We encourage our community to develop their own pluggable modules.</p><p>Core framework, dashboard and a few plugin modules such as modbus-tcp, mqtt and eKuiper are open source under LGPLv3 license. GridBeat may run with these open source modules without an EMQ license. But all other commercial plugin modules require an official EMQ license to run without limitation.</p><p>A trial EMQ license can be download from our <a href="https://www.emqx.com/en/apply-licenses/gridbeat" target="_blank" rel="noreferrer">official website</a>. All available modules could be used with limitation on 100 connections and 1000 data tags for 15 days. If trial EMQ license is expired, you can apply the trial EMQ license via our official website again. However, a mailbox can only apply for a trial license up to two times.</p><p>Of course, you can also directly <a href="https://www.emqx.com/en/contact?product=gridbeat" target="_blank" rel="noreferrer">contact us</a> to obtain the official license.</p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>When you applies for trial License from official website, you must use hardware token to bind the equipment.</p><p>You can contact us directly to apply for a License that does not require hardware token to bind the equipment.</p></div><h2 id="step-1-check-the-hardware-token" tabindex="-1">Step 1 Check the hardware token <a class="header-anchor" href="#step-1-check-the-hardware-token" aria-label="Permalink to “Step 1 Check the hardware token”">​</a></h2><p>Click <strong>System Information -&gt; About</strong> to view the hardware logo and copy it.</p><h2 id="step-2-apply-for-license" tabindex="-1">Step 2 Apply for license <a class="header-anchor" href="#step-2-apply-for-license" aria-label="Permalink to “Step 2 Apply for license”">​</a></h2><p>Go to the <a href="https://www.emqx.com/en/apply-licenses/gridbeat" target="_blank" rel="noreferrer">official website</a> and fill in relevant information to apply for the license. The license will be sent to your mailbox.</p><h2 id="step-3-install-license" tabindex="-1">Step 3 Install License <a class="header-anchor" href="#step-3-install-license" aria-label="Permalink to “Step 3 Install License”">​</a></h2><p>To install a license, as shown below.</p><p><img src="'+n+'" alt="license-null"></p><ul><li>Click <code>License</code> from the System Information drop-down box in the upper-right corner.</li><li>Click <code>Upload</code> button to select the license file and then submit.</li></ul><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>When applying for a valid license, you need to fill in the hardware token.</p><p>The pluggable modules of the commercial version cannot be used when the license has not been uploaded or the license has expired.</p><p>Users can apply for a trial license from official website by clicking <code>Apply</code>, or contact our sales representatives to purchase a commercial license by clicking <code>Contact us</code>.</p></div><h2 id="step-4-check-over-the-license-details" tabindex="-1">Step 4 Check over the License details <a class="header-anchor" href="#step-4-check-over-the-license-details" aria-label="Permalink to “Step 4 Check over the License details”">​</a></h2><p>After the license is successfully installed, it will display the license information.</p><p>The license page details includes following items.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Content</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;">Effective data</td><td style="text-align:left;">Time when GridBeat applied for License to take effect</td></tr><tr><td style="text-align:left;">Expire date</td><td style="text-align:left;">If the license has expired, the system would not work correctly anymore. Users must obtain a new valid license from official website, Re-upload the new license as procedure above</td></tr><tr><td style="text-align:left;">Limit on the maximum number of nodes</td><td style="text-align:left;">The maximum number of connection nodes that GridBeat can create, a node can be either a southbound device or a northbound application</td></tr><tr><td style="text-align:left;">Limit on the maximum number of tags</td><td style="text-align:left;">The maximum number of total data tags that GridBeat can create</td></tr><tr><td style="text-align:left;">Enabled Plugins</td><td style="text-align:left;">List of all the authorized pluggable modules for this license.Each commercial plugin module can be authorized independently in EMQ license</td></tr></tbody></table>',19)])])}const f=t(o,[["render",s]]);export{m as __pageData,f as default};
